    39→    // For every new connection, the connection manager will determine which
    40→    // codec to use. This mode supports both ALPN for TLS listeners as well as
    41→    // protocol inference for plaintext listeners. If ALPN data is available, it
    42→    // is preferred, otherwise protocol inference is used. In almost all cases,
    43→    // this is the right option to choose for this setting.
    44→    AUTO = 0;
    45→
    46→    // The connection manager will assume that the client is speaking HTTP/1.1.
    47→    HTTP1 = 1;
    48→
    49→    // The connection manager will assume that the client is speaking HTTP/2
    50→    // (Envoy does not require HTTP/2 to take place over TLS or to use ALPN.
    51→    // Prior knowledge is allowed).
    52→    HTTP2 = 2;
    53→
    54→    // [#not-implemented-hide:] QUIC implementation is not production ready yet. Use this enum with
    55→    // caution to prevent accidental execution of QUIC code. I.e. `!= HTTP2` is no longer sufficient
    56→    // to distinguish HTTP1 and HTTP2 traffic.
    57→    HTTP3 = 3;
