    74→  // header.
    75→  enum ForwardClientCertDetails {
    76→    // Do not send the XFCC header to the next hop. This is the default value.
    77→    SANITIZE = 0;
    78→
    79→    // When the client connection is mTLS (Mutual TLS), forward the XFCC header
    80→    // in the request.
